<div class="row justify-content-center building-history">
    <div class="col-12 col-md-4 col-lg-3 text-center mb-3">
        <img loading="lazy" src="/res/img/marker.jpg" alt="Odd Fellows Lodge 225 Historical Marker" class="img-fluid" style="border-radius:8px;">
